CREATE TABLE IF NOT EXISTS user_preferences (
  id int NOT NULL AUTO_INCREMENT,
  ownerUserId int NOT NULL,
  alwaysRequireKimiApproval boolean NOT NULL DEFAULT true,
  createdAt bigint NOT NULL,
  updatedAt bigint NOT NULL,
  PRIMARY KEY (id),
  UNIQUE KEY user_preferences_owner_unique_idx (ownerUserId)
);
ALTER TABLE orchestration_turns MODIFY COLUMN state enum('received','routing','credential_check','context_assembly','model_calling','awaiting_approval','model_review','persisting_output','completed','blocked','failed','stopped') NOT NULL DEFAULT 'received';
ALTER TABLE orchestration_turns ADD COLUMN approvalStatus enum('not_required','awaiting_owner','approved','revision_requested','cancelled') NOT NULL DEFAULT 'not_required' AFTER credentialStateJson;
ALTER TABLE orchestration_turns ADD COLUMN approvalPlanContent longtext NULL AFTER approvalStatus;
ALTER TABLE orchestration_turns ADD COLUMN approvalDecisionMessage longtext NULL AFTER approvalPlanContent;
ALTER TABLE orchestration_turns ADD COLUMN approvalRequestedAt bigint NULL AFTER approvalDecisionMessage;
ALTER TABLE orchestration_turns ADD COLUMN approvalResolvedAt bigint NULL AFTER approvalRequestedAt;

